<template><div v-if="open" class="sc-design-drawer-backdrop" @mousedown.self="$emit('close')" @keydown.esc="$emit('close')"><aside ref="drawer" class="sc-design-drawer" role="dialog" aria-modal="true" :aria-labelledby="titleId" tabindex="-1"><header><h2 :id="titleId">{{ title }}</h2><ScIconButton :label="closeLabel" @click="$emit('close')"><ScIcon name="close" /></ScIconButton></header><slot /></aside></div></template>
<script setup lang="ts">import { nextTick,ref,useId,watch } from 'vue'; import ScIcon from './ScIcon.vue'; import ScIconButton from './ScIconButton.vue'; const props=withDefaults(defineProps<{open:boolean;title:string;closeLabel?:string}>(),{closeLabel:'关闭'}); defineEmits<{close:[]}>(); const drawer=ref<HTMLElement|null>(null); const titleId=`sc-drawer-${useId()}`; watch(()=>props.open,async(open)=>{if(open){await nextTick();drawer.value?.focus();}});</script>
<style scoped>.sc-design-drawer-backdrop{position:fixed;inset:0;z-index:1000;display:flex;justify-content:flex-end;background:var(--sc-app-overlay)}.sc-design-drawer{width:min(90vw,420px);height:100%;overflow:auto;padding:calc(var(--sc-component-panel-padding) * 1px);background:var(--sc-app-panel);box-shadow:var(--sc-app-shadow-modal)}.sc-design-drawer>header{display:flex;align-items:center;justify-content:space-between;gap:var(--sc-product-space-2)}.sc-design-drawer h2{margin:0;font-size:var(--sc-product-text-section)}</style>
